        log("[LOAD] Loading sleep-centered data from step02...")
        sleep_input_path = RQ_DIR / "data" / "step02_sleep_centered.csv"
        
        if not sleep_input_path.exists():
            log(f"[ERROR] Sleep input file not found: {sleep_input_path}")
